VALUES
  ('aboriginal-57f41407-moex-00012', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列有關原住民選舉權的敘述，何者錯誤？', '["某甲為平地原住民，若想競選立法委員，只能登記參選平地原住民立法委員", "某乙為平地原住民，戶籍設於某縣市，該縣市並無平地原住民議員席次，某乙可登記為區域議員候選人", "某丙為山地原住民，戶籍設於某縣市，該縣市設有山地原住民議員席次，但某丙可選擇登記為區域議員 候選人", "某丁為山地原住民，戶籍設於花蓮縣，立法委員選舉時，某丁無法投票給花蓮縣區域立法委員候選人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00013', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '1980年代臺灣原住民族權利促進會曾發布臺灣原住民族權利宣言，提出17項權利訴求，其中一項為原住 民族有權成立自己的學校。請問下列那一項現行實施之制度，最接近該訴求的精神？', '["原住民重點學校", "原住民族實驗教育學校", "大專校院原住民專班", "大專校院原住民族學院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00014', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依照原住民族基本法的規定，原住民得在原住民族地區及經中央原住民族主管機關公告之海域，依法從事 下列非營利行為：', '["獵捕野生動物，以傳統文化、祭儀或自用為限", "採集野生植物及菌類", "採取礦物、土石", "利用空中資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00015', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列何者不是原住民族健康法制定的目的？', '["促進原住民族健康", "建構以原住民族為主體之健康政策", "改善原住民族健康不平等情形", "降低原住民族死亡率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00016', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依照原住民族基本法的規定，政府為何成立財團法人原住民族文化事業基金會，規劃辦理原住民族專屬及 使用族語之傳播媒介與機構？', '["保障原住民族傳播及媒體近用權", "宣揚原住民族文化", "增加族群傳播的國際能見度", "培育原住民族文化人才"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00017', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '請問原住民族健康法的中央主管機關為何？', '["原住民族委員會", "衛生福利部", "國民健康署", "環境部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00018', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '下列何者不是原住民族基本法制定的目的？', '["符合聯合國原住民族權利宣言", "保障原住民族基本權利", "促進原住民族生存發展", "建立共存共榮之族群關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00019', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '依照原住民族健康法的規定，醫療機構、護理機構、老人福利機構、長期照顧服務機構及其他健康照護服 務機構應鼓勵所屬人員修習何種課程，以提升原住民族健康照護之服務品質？', '["原民文化概論", "原住民族文化安全", "原住民族健康概論", "原住民族基本法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00020', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '為協助地方政府執行前瞻基礎建設計畫有關原住民族部落營造相關工作，原住民族委員會訂定計畫補助地 方政府進用專案人力，以提升執行效能。根據最近一期補助計畫內容，下列有關該項專案人力補助計畫之 敘述，何者正確？', '["進用之專案人力限為具原住民身分者", "補助對象限轄有文化健康站之直轄市及縣市政府", "專案人力所需費用採全額補助", "專案人力工作項目包括協助提升前瞻基礎建設部落營造工作項下各工程進度執行率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00021', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-2d8844e1', 'sub-aboriginal-57f41407-01', NULL, 'single_choice', '原住民族委員會刻正執行都市地區原住民族發展方案（112年～116年），請問下列對該方案之敘述，何者 錯誤？', '["依該方案內容說明，目前原住民人口設籍於非原住民族地區者已近5成", "該方案嘗試透過都市地區教會開設族語學習班，以提高族語認證通過率", "該方案具體措施包括將原住民族文化健康站設置工作擴展至都會區", "在該方案項下，由客家委員會推動原住民族與客家青年體育交流活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "9cfc8d4cd2ef", "answer_pdf_sha1": "df34663e5856", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
